import static com.ibm.integration.test.v1.Matchers.equalsMessage;
import static com.ibm.integration.test.v1.Matchers.nodeCallCountIs;
import static com.ibm.integration.test.v1.Matchers.terminalPropagateCountIs;
import static org.hamcrest.MatcherAssert.assertThat;

import java.io.InputStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import com.ibm.integration.test.v1.NodeSpy;
import com.ibm.integration.test.v1.SpyObjectReference;
import com.ibm.integration.test.v1.TestMessageAssembly;
import com.ibm.integration.test.v1.TestSetup;
import com.ibm.integration.test.v1.exception.TestException;

mandatory_cleanup.code:
@AfterEach
public void cleanupTest() throws TestException {
    TestSetup.restoreAllMocks();
}

critical_rule.real_api:
// ── Populating ────────────────────────────────────────────────────────────────
assembly.buildFromRecordedMessageAssembly(InputStream stream);
    // Loads a recorded .mxml checkpoint. This is the ONLY way to populate an assembly.

// ── Comparing ─────────────────────────────────────────────────────────────────
// Use the Hamcrest matcher — do NOT call comparison methods directly on the object:
assertThat(actualAssembly, equalsMessage(expectedAssembly));
assertThat(actualAssembly, equalsMessage(expectedAssembly).ignorePath("/path/to/field", false));

// ── Retrieving from NodeSpy ───────────────────────────────────────────────────
TestMessageAssembly out = nodeSpy.propagatedMessageAssembly("out", 1);
    // Gets the Nth message propagated from the named terminal (1-based index).
TestMessageAssembly in  = nodeSpy.receivedMessageAssembly("in", 1);
    // Gets the Nth message received at the named terminal (used in whole-flow tests).

helper_method_load_assembly.code:
private TestMessageAssembly loadAssembly(String resourcePath) throws TestException {
    TestMessageAssembly assembly = new TestMessageAssembly();
    try {
        InputStream stream = Thread.currentThread()
                .getContextClassLoader()
                .getResourceAsStream(resourcePath);
        if (stream == null) {
            throw new TestException("Cannot find recorded message: " + resourcePath);
        }
        assembly.buildFromRecordedMessageAssembly(stream);
    } catch (Exception ex) {
        throw new TestException("Failed to load recorded message: " + resourcePath, ex);
    }
    return assembly;
}

pattern.code:
@Test
@DisplayName("[FLOW] — [NODE] TC001 — [description] (recorded)")
public void [flow]_[Node]_TC001() throws TestException {

    // Spy on the node under test
    SpyObjectReference nodeRef = new SpyObjectReference()
            .application("[APP]")
            .messageFlow("[FLOW]")
            .node("[NODE]");

    NodeSpy nodeSpy = new NodeSpy(nodeRef);

    // Inject the recorded input checkpoint
    TestMessageAssembly inputAssembly = loadAssembly("/[INPUT].mxml");

    // Execute the node
    nodeSpy.evaluate(inputAssembly, true, "in");

    // Assert the node was called once
    assertThat(nodeSpy, nodeCallCountIs(1));

    // Assert it propagated via the expected terminal
    assertThat(nodeSpy, terminalPropagateCountIs("[TERMINAL]", 1));

    // Get the actual output and compare to the recorded expected output
    TestMessageAssembly actualOutput   = nodeSpy.propagatedMessageAssembly("[TERMINAL]", 1);
    TestMessageAssembly expectedOutput = loadAssembly("/[EXPECTED].mxml");

    assertThat(actualOutput, equalsMessage(expectedOutput));
}

nodeSpy.evaluate(inputAssembly, true, "in");
assertThat(nodeSpy, nodeCallCountIs(1));
assertThat(nodeSpy, terminalPropagateCountIs("out", 1));
// No equalsMessage — just verifying routing behaviour

@Test
@DisplayName("WholeFlow — Normal path — input arrives at expected output nodes")
public void wholeFlow_FlowOrder_Test() throws TestException {

    // 1. Spy on the INPUT node to inject the recorded message
    SpyObjectReference inputNodeRef = new SpyObjectReference()
            .application("[AppName]")
            .messageFlow("[FlowName]")
            .node("[MQInputNodeLabel]");   // label of the MQ Input node

    NodeSpy inputNodeSpy = new NodeSpy(inputNodeRef);

    // 2. Stub OUTPUT nodes to prevent real MQ writes
    SpyObjectReference output1Ref = new SpyObjectReference()
            .application("[AppName]")
            .messageFlow("[FlowName]")
            .node("[OutputNode1Label]");   // label of the first MQ Output node

    NodeStub output1Stub = new NodeStub(output1Ref);
    output1Stub.setStopAtInputTerminal("in");    // intercept before the node fires

    SpyObjectReference output2Ref = new SpyObjectReference()
            .application("[AppName]")
            .messageFlow("[FlowName]")
            .node("[OutputNode2Label]");

    NodeStub output2Stub = new NodeStub(output2Ref);
    output2Stub.setStopAtInputTerminal("in");

    // 3. Stub the HTTP Request node inside the subflow to mock the external service
    SpyObjectReference httpRequestRef = new SpyObjectReference()
            .application("[AppName]")
            .messageFlow("[FlowName]")
            .subflowNode("[SubflowInstanceLabel]")  // subflow instance label
            .node("[HTTPRequestNodeLabel]");         // node inside the subflow

    NodeStub httpRequestStub = new NodeStub(httpRequestRef);
    // Provide a recorded response to feed back into the flow
    TestMessageAssembly mockResponse = loadAssembly("/recorded_http_response.mxml");
    httpRequestStub.setReturnValue(mockResponse, "out");   // replay recorded response

    // 4. Inject the input message
    TestMessageAssembly inputMsg = loadAssembly("/[messageId]-0.mxml");
    inputNodeSpy.evaluate(inputMsg, true, "out");          // drive from input node

    // 5. Assert messages arrived at expected output stubs
    assertThat(output1Stub, nodeCallCountIs(1));
    assertThat(output2Stub, nodeCallCountIs(1));

    // 6. Optionally compare content against recorded expected assemblies
    assertThat(output1Stub.propagatedMessageAssembly("in", 1),
            equalsMessage(loadAssembly("/[messageId]-expected.mxml")));
}

parameterized_test_patterns.required_imports:
package com.[org].[app].tests;

import static com.ibm.integration.test.v1.Matchers.equalsMessage;
import static org.hamcrest.MatcherAssert.assertThat;

import java.io.InputStream;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Disabled;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.CsvSource;

import com.ibm.integration.test.v1.NodeSpy;
import com.ibm.integration.test.v1.NodeStub;
import com.ibm.integration.test.v1.SpyObjectReference;
import com.ibm.integration.test.v1.TestMessageAssembly;
import com.ibm.integration.test.v1.TestSetup;
import com.ibm.integration.test.v1.exception.TestException;

core_pattern.template:
class WholeFlow_[AppName]_Tests {

    @AfterEach
    public void cleanupTest() throws TestException {
        TestSetup.restoreAllMocks();
    }

    @ParameterizedTest
    //           Input Message              Expected messages
    @CsvSource({"[messageId]-0.mxml,        [messageId]-N.mxml"})
    public void WholeFlow_[ScenarioName]_Test(
            String inputMXMLName,
            String outputMXMLName) throws TestException {

        // --- 1. Define SpyObjectReferences ---
        SpyObjectReference inputNodeRef = new SpyObjectReference()
                .application("[AppName]").messageFlow("[FlowName]").node("[InputNodeLabel]");
        SpyObjectReference outputNodeRef = new SpyObjectReference()
                .application("[AppName]").messageFlow("[FlowName]").node("[OutputNodeLabel]");

        // --- 2. Initialize NodeSpy objects ---
        NodeSpy inputNodeSpy  = new NodeSpy(inputNodeRef);
        NodeSpy outputNodeSpy = new NodeSpy(outputNodeRef);

        // --- 3. Stop output nodes before they write to real queues/files ---
        outputNodeSpy.setStopAtInputTerminal("in");

        // --- 4. Load and inject the input message (inline — name comes from @CsvSource) ---
        TestMessageAssembly inputMessageAssembly = new TestMessageAssembly();
        inputMessageAssembly.buildFromRecordedMessageAssembly(
                Thread.currentThread().getContextClassLoader().getResourceAsStream(inputMXMLName));

        inputNodeSpy.propagate(inputMessageAssembly, "out");

        // --- 5. Retrieve actual output ---
        TestMessageAssembly outputMessageAssembly = outputNodeSpy.receivedMessageAssembly("in", 1);

        // --- 6. Load expected and assert ---
        TestMessageAssembly expectedMessageAssembly = new TestMessageAssembly();
        expectedMessageAssembly.buildFromRecordedMessageAssembly(
                Thread.currentThread().getContextClassLoader().getResourceAsStream(outputMXMLName));

        assertThat(outputMessageAssembly, equalsMessage(expectedMessageAssembly));
    }
}

variant.code:
@ParameterizedTest
//           Input Message              Mock Messages               Expected messages
@CsvSource({"[messageId]-0.mxml,        [messageId]-12.mxml,        [messageId]-10.mxml, [messageId]-9.mxml"})
public void WholeFlow_FlowOrder_Test(
        String inputMXMLName,
        String mockHttpMXMLName,
        String output1ExpectedMXMLName,
        String output2ExpectedMXMLName) throws TestException {

    SpyObjectReference inputRef   = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[InputNode]");
    SpyObjectReference output1Ref = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[OutputNode1]");
    SpyObjectReference output2Ref = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[OutputNode2]");

    NodeSpy inputSpy   = new NodeSpy(inputRef);
    NodeSpy output1Spy = new NodeSpy(output1Ref);
    NodeSpy output2Spy = new NodeSpy(output2Ref);

    output1Spy.setStopAtInputTerminal("in");
    output2Spy.setStopAtInputTerminal("in");

    TestMessageAssembly inputAssembly = new TestMessageAssembly();
    inputAssembly.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(inputMXMLName));
    inputSpy.propagate(inputAssembly, "out");

    TestMessageAssembly actualOutput1 = output1Spy.receivedMessageAssembly("in", 1);
    TestMessageAssembly actualOutput2 = output2Spy.receivedMessageAssembly("in", 1);

    TestMessageAssembly expectedOutput1 = new TestMessageAssembly();
    expectedOutput1.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(output1ExpectedMXMLName));
    TestMessageAssembly expectedOutput2 = new TestMessageAssembly();
    expectedOutput2.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(output2ExpectedMXMLName));

    assertThat(actualOutput1, equalsMessage(expectedOutput1));
    assertThat(actualOutput2, equalsMessage(expectedOutput2));
}

SpyObjectReference httpRequestRef = new SpyObjectReference()
        .application("[AppName]").messageFlow("[FlowName]")
        .subflowNode("[SubflowInstanceLabel]")
        .node("[HTTPRequestNodeLabel]");

NodeSpy httpRequestSpy = new NodeSpy(httpRequestRef);
httpRequestSpy.setStopAtInputTerminal("in");
httpRequestSpy.setStopAtOutputTerminal("out");

SpyObjectReference httpRequestRef = new SpyObjectReference()
        .application("[AppName]").messageFlow("[FlowName]")
        .subflowNode("[SubflowInstanceLabel]")
        .node("[HTTPRequestNodeLabel]");

NodeStub httpRequestStub = new NodeStub(httpRequestRef);

TestMessageAssembly mockResponse = new TestMessageAssembly();
mockResponse.buildFromRecordedMessageAssembly(
        Thread.currentThread().getContextClassLoader().getResourceAsStream(mockHttpMXMLName));

httpRequestStub.onCall().propagatesMessage("in", "out", mockResponse);

@ParameterizedTest
//           Input Message              Expected messages
@CsvSource({"[messageId]-13.mxml,       [messageId]-14.mxml, [messageId]-16.mxml"})
public void WholeFlow_LogError_Test(
        String inputMXMLName,
        String output1ExpectedMXMLName,
        String errorOutputExpectedMXMLName) throws TestException {

    SpyObjectReference inputRef   = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[InputNode]");
    SpyObjectReference output1Ref = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[OutputNode1]");
    SpyObjectReference errorRef   = new SpyObjectReference()
            .application("[AppName]").messageFlow("[FlowName]").node("[ErrorOutputNode]");

    NodeSpy inputSpy   = new NodeSpy(inputRef);
    NodeSpy output1Spy = new NodeSpy(output1Ref);
    NodeSpy errorSpy   = new NodeSpy(errorRef);

    output1Spy.setStopAtInputTerminal("in");
    errorSpy.setStopAtInputTerminal("in");

    TestMessageAssembly inputAssembly = new TestMessageAssembly();
    inputAssembly.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(inputMXMLName));

    inputSpy.propagate(inputAssembly, "catch");   // drive the error path

    TestMessageAssembly actualOutput1 = output1Spy.receivedMessageAssembly("in", 1);
    TestMessageAssembly actualError   = errorSpy.receivedMessageAssembly("in", 1);

    TestMessageAssembly expectedOutput1 = new TestMessageAssembly();
    expectedOutput1.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(output1ExpectedMXMLName));
    TestMessageAssembly expectedError = new TestMessageAssembly();
    expectedError.buildFromRecordedMessageAssembly(
            Thread.currentThread().getContextClassLoader().getResourceAsStream(errorOutputExpectedMXMLName));

    assertThat(actualOutput1, equalsMessage(expectedOutput1));
    assertThat(actualError,   equalsMessage(expectedError));
}

